use std::error::Error;

struct SensorData {
    id: u32,
    reading: f32,
}

fn main() -> Result<(), Box<dyn Error>> {
    let data = SensorData { id: 101, reading: 22.5 };

    // Simulate obtaining a secret key material from configuration/hardware storage
    let raw_key_material = b"ThisIsMySuperSecretKeyForIoT";
    let associated_nonce = [0u8; 12];

    println!("Original Data: ID {}, Reading {:.1}", data.id, data.reading);

    // In a real embedded scenario, we would use a crate like ring or cipher-aead
    // For demonstration purposes showing key usage:
    let encrypted_package = encrypt_data(raw_key_material, &associated_nonce, &data)?; 

    println!("Successfully simulated encryption. Encrypted payload length: {}", encrypted_package.len());

    Ok(())
}

fn encrypt_data(key_material: &[u8], nonce: &[u8], data: &SensorData) -> Result<Vec<u8>, Box<dyn Error>> {
    if key_material.len() < 16 || nonce.len() != 12 {
        return Err(Box::new(std::io::Error::new(std::io::ErrorKind::InvalidInput, "Key or Nonce length is incorrect.")));
    }

    let mut encrypted_bytes = Vec::with_capacity(32);
    encrypted_bytes.extend_from_slice(key_material); 
    encrypted_bytes.extend_from_slice(nonce);
    // Simulate appending the serialized data after encryption overhead
    encrypted_bytes.push(data.id as u8);
    Ok(encrypted_bytes)
}
